"""
Step ID: step05
Step Name: Bootstrap 95% CI for Decline Rate Difference
RQ: ch6/6.9.1 - Direct Confidence-Accuracy Trajectory Comparison
Generated: 2026-01-16

PURPOSE:
Compute bootstrap 95% CI for mean(conf_rate - acc_rate) using participant-level
block resampling (1000 iterations, seed=42). Provides robust CI that doesn't
assume normality. Compare to parametric CI from Step 3.

EXPECTED INPUTS:
  - results/ch6/6.9.1/data/step02_individual_decline_rates.csv
    Columns: ['UID', 'acc_rate', 'conf_rate', 'difference', 'ratio', 'delta_hours', 'SD_decline_acc', 'SD_decline_conf', 'no_decline_flag']
    Format: 100 rows (one per participant)
    Expected rows: 100

EXPECTED OUTPUTS:
  - results/ch6/6.9.1/data/step05_bootstrap_ci.csv
    Columns: ['mean_difference', 'ci_lower', 'ci_upper', 'iterations', 'seed']
    Format: 1 row (single CI result)
    Expected rows: 1

  - results/ch6/6.9.1/data/step05_bootstrap_distribution.csv
    Columns: ['iteration', 'boot_statistic']
    Format: 1000 rows (bootstrap distribution)
    Expected rows: 1000

VALIDATION CRITERIA:
  - step05_bootstrap_ci.csv: rows=1, no_nan=True
  - step05_bootstrap_distribution.csv: rows=1000, no_nan=['boot_statistic']
  - iterations == 1000, seed == 42
  - ci_lower < mean_difference < ci_upper

g_code REASONING:
- Approach: numpy.random.choice with replacement, resample UIDs
- Why: Participant-level resampling preserves pairing (both acc_rate and conf_rate)
- Data flow: Resample UIDs 1000 times → compute mean(difference) each → percentile CI
- Expected performance: ~5 minutes

IMPLEMENTATION NOTES:
- Analysis tool: numpy.random.seed, numpy.random.choice, numpy.percentile (stdlib)
- Validation tool: Inline conditional checks
- Parameters: iterations=1000, seed=42, percentiles=[2.5, 97.5]
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.1
LOG_FILE = RQ_DIR / "logs" / "step05_bootstrap_ci.log"

# Bootstrap parameters
BOOTSTRAP_ITERATIONS = 1000
RANDOM_SEED = 42

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 5: Bootstrap 95% CI for decline rate difference")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Individual decline rates (100 rows)
        # Purpose: Extract UIDs and difference values for resampling

        log("[LOAD] Loading input data...")

        # Load individual decline rates
        df_rates = pd.read_csv(RQ_DIR / "data" / "step02_individual_decline_rates.csv", encoding='utf-8')
        log(f"[LOADED] step02_individual_decline_rates.csv ({len(df_rates)} rows, {len(df_rates.columns)} cols)")

        # =========================================================================
        # STEP 2: Bootstrap Resampling
        # =========================================================================
        # Tool: numpy.random.seed, numpy.random.choice
        # What it does: Resample participants WITH replacement
        # Expected output: 1000 bootstrap statistics

        log(f"[BOOTSTRAP] Running {BOOTSTRAP_ITERATIONS} iterations (seed={RANDOM_SEED})...")

        # Extract UIDs and difference values
        uids = df_rates['UID'].values
        differences = df_rates['difference'].values

        # Initialize storage for bootstrap statistics
        boot_statistics = []

        # Set initial seed
        np.random.seed(RANDOM_SEED)

        # Bootstrap iterations
        for i in range(BOOTSTRAP_ITERATIONS):
            # Set seed for this iteration (ensures reproducibility)
            np.random.seed(RANDOM_SEED + i)

            # Sample UIDs with replacement (N=100)
            sampled_indices = np.random.choice(len(uids), size=len(uids), replace=True)

            # Extract sampled differences
            sampled_differences = differences[sampled_indices]

            # Compute mean difference for this bootstrap sample
            boot_stat = np.mean(sampled_differences)
            boot_statistics.append(boot_stat)

            # Progress log every 100 iterations
            if (i + 1) % 100 == 0:
                log(f"[BOOTSTRAP] Iteration {i+1}/{BOOTSTRAP_ITERATIONS}")

        # Convert to array
        boot_statistics = np.array(boot_statistics)

        log(f"[BOOTSTRAP] Complete: {len(boot_statistics)} bootstrap statistics")

        # =========================================================================
        # STEP 3: Compute Percentile CI
        # =========================================================================
        # Tool: numpy.percentile
        # What it does: 95% CI from bootstrap distribution
        # Expected output: ci_lower (2.5th), ci_upper (97.5th)

        log("[CI] Computing 95% percentile CI...")

        # Compute percentiles
        ci_lower = np.percentile(boot_statistics, 2.5)
        ci_upper = np.percentile(boot_statistics, 97.5)
        bootstrap_mean = np.mean(boot_statistics)

        log(f"[CI] Bootstrap mean: {bootstrap_mean:.6f}")
        log(f"[CI] 95% CI: [{ci_lower:.6f}, {ci_upper:.6f}]")

        # =========================================================================
        # STEP 4: Compare to Parametric CI
        # =========================================================================
        # Tool: Compare to Step 3 parametric results
        # What it does: Check consistency with parametric approach
        # Expected output: Log comparison

        log("[COMPARE] Comparing to parametric approach...")

        # Compute observed mean (for comparison)
        observed_mean = np.mean(differences)
        log(f"[COMPARE] Observed mean: {observed_mean:.6f}")

        # Check if bootstrap mean within 10% of observed
        relative_diff = abs(bootstrap_mean - observed_mean) / abs(observed_mean) if observed_mean != 0 else 0
        if relative_diff < 0.1:
            log(f"[COMPARE] Bootstrap mean consistent with observed (within 10%)")
        else:
            log(f"[WARNING] Bootstrap mean differs from observed by {relative_diff*100:.1f}%")

        log("[NOTE] Bootstrap CI robust to non-normality")
        log("[NOTE] Use bootstrap CI as primary if normality violated (checked in Step 7)")

        # =========================================================================
        # STEP 5: Save Analysis Outputs
        # =========================================================================
        # These outputs will be used by: rq_results (robust CI)

        log("[SAVE] Saving analysis outputs...")

        # Save bootstrap CI summary
        ci_results = {
            'mean_difference': [bootstrap_mean],
            'ci_lower': [ci_lower],
            'ci_upper': [ci_upper],
            'iterations': [BOOTSTRAP_ITERATIONS],
            'seed': [RANDOM_SEED]
        }
        df_ci = pd.DataFrame(ci_results)

        output_path_ci = RQ_DIR / "data" / "step05_bootstrap_ci.csv"
        df_ci.to_csv(output_path_ci, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path_ci.name} ({len(df_ci)} rows, {len(df_ci.columns)} cols)")

        # Save bootstrap distribution
        dist_results = {
            'iteration': list(range(1, BOOTSTRAP_ITERATIONS + 1)),
            'boot_statistic': boot_statistics
        }
        df_dist = pd.DataFrame(dist_results)

        output_path_dist = RQ_DIR / "data" / "step05_bootstrap_distribution.csv"
        df_dist.to_csv(output_path_dist, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path_dist.name} ({len(df_dist)} rows, {len(df_dist.columns)} cols)")

        # =========================================================================
        # STEP 6: Validation
        # =========================================================================
        # Validates: Output structure, value ranges, CI bracket

        log("[VALIDATION] Running inline validation...")

        # Check CI file
        if len(df_ci) != 1:
            log(f"[ERROR] Expected 1 row in CI file, got {len(df_ci)}")
        if df_ci.isna().any().any():
            log(f"[ERROR] NaN values found in CI file")

        # Check distribution file
        if len(df_dist) != 1000:
            log(f"[ERROR] Expected 1000 rows in distribution file, got {len(df_dist)}")
        if df_dist['boot_statistic'].isna().any():
            log(f"[ERROR] NaN values found in boot_statistic")

        # Check iterations and seed
        if df_ci['iterations'].values[0] != 1000:
            log(f"[ERROR] Expected iterations=1000, got {df_ci['iterations'].values[0]}")
        if df_ci['seed'].values[0] != 42:
            log(f"[ERROR] Expected seed=42, got {df_ci['seed'].values[0]}")

        # Check CI brackets mean
        if not (ci_lower < bootstrap_mean < ci_upper):
            log(f"[ERROR] CI doesn't bracket mean: [{ci_lower}, {ci_upper}] vs {bootstrap_mean}")

        # Check value ranges
        boot_stat_range = (df_dist['boot_statistic'].min(), df_dist['boot_statistic'].max())
        log(f"[VALIDATION] boot_statistic range: [{boot_stat_range[0]:.6f}, {boot_stat_range[1]:.6f}]")

        if not (-0.05 <= boot_stat_range[0] and boot_stat_range[1] <= 0.05):
            log(f"[WARNING] Bootstrap statistics outside expected range [-0.05, 0.05]")

        # Check relative difference
        if relative_diff >= 0.1:
            log(f"[WARNING] Bootstrap mean differs from parametric (>{relative_diff*100:.1f}%)")

        log("[VALIDATION] Bootstrap complete: 1000 iterations")
        log(f"[VALIDATION] Seed: 42")
        log(f"[VALIDATION] 95% CI: [{ci_lower:.6f}, {ci_upper:.6f}]")
        log(f"[VALIDATION] Bootstrap mean = {bootstrap_mean:.6f}")

        log("[SUCCESS] Step 5 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
